VALUES
  ('elementary-f29af906-moex-00218', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '某國國會眾議院大選剛落幕，現任總理所屬的執政黨「不滿公民行動」痛失第一大黨地位，兩大反對聯盟 「一起」和「海盜和市長」合計席次過半，已宣布合作組閣，產生新的政府。該國應屬於那種政府體制？', '["內閣制", "總統制", "混合制", "委員會制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00219', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '甲借錢給設籍高雄但久居新北市某公寓的乙，乙未依約定即時還款並有持續拖延之傾向，請問甲該如何救 濟其權利？', '["僅得向高雄地方法院提起民事訴訟", "訴訟前應先向調解委員會申請調解", "甲乙於法院審理中得成立和解方案", "甲必須聘請律師方可提出民事訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00220', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '下列四則新聞標題，何者合乎相關法規？', '["被告欲繳罰金，檢察官拒絕易科罰金並發監執行", "酒駕犯獲緩起訴，民眾抨擊法官縱容酒駕", "酒測值誤差獲無罪，公設辯護人為酒駕被害人上訴", "正義波麗士，熱血員警為被害人提出公訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00221', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '有民眾攜帶寵物蛇搭乘自強號，寵物蛇爬行到車廂屋頂處造成乘客恐慌。嗣後臺鐵表示要依法追究飼主之 責任，並依據法律對行為違反規定的飼主施以處罰，其處罰性質與下列選項何者相同？', '["因故意或過失，不法侵害他人之權利者", "擅自以公開播送方法侵害他人之著作財產權者", "私行拘禁或以其他非法方法，剝奪人之行動自由者", "因違反鐵路法規而處以罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00222', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '依司法院大法官解釋，關於集會遊行自由，下列敘述何者正確？', '["群眾因特殊原因未經召集自發聚集之偶發性集會遊行，自然無法事先申請許可，因此集會遊行法的事前 許可制，應排除於偶發性集會遊行之適用", "集會遊行法針對一般集會遊行仍採取事前許可制，已嚴重侵害人民之集會遊行自由而屬於違憲", "集會遊行是人民表達自身訴求的重要手段，因此縱使是國家針對無關集會遊行內容與目的之時間、地點 及方式進行限制，也必須受嚴格審查", "為使主管機關得以保障人民權利，並降低集會遊行對社會秩序之影響，因此緊急性集會遊行仍須於 24 小時前進行事前申請，並無違反憲法意旨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00223', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '國家為一定政策目標之需要，對於有特定關係之國民所課徵，並將課徵所得之金錢建立特別基金，專供該 特定目標達成。此種公法上負擔，學理上稱為：', '["怠金", "國債", "特別公課", "間接稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00224', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '憲法第20條規定，人民有依法服兵役之義務。關於憲法所稱的兵役義務，下列敘述何者正確？', '["兵役體位之判斷是徵兵機關之事實調查行為，在性質上屬於行政事實行為，受判定之役男縱不服而認有 違法或不當情事，亦不得提起訴訟", "基於男女生理上之差異，以及此種差異所生之社會生活功能角色之不同，現行兵役義務限於成年男性， 仍無違平等原則", "大法官曾認為對於因宗教理由而無法服戰鬥兵役之人民，兵役法未設有例外處置而逕以刑罰相繩，已屬 對人民信仰自由的過度侵害而宣告違憲", "為兼顧軍紀維護與軍事安全，因此我國設有軍事審判法，對於服義務役之現役軍人若涉及刑事案件，縱 於非戰時亦歸軍事法院審理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00225', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '法律解釋的方法有許多種，例如刑法第293條所稱之無自救能力之人，包括植物人。前述內容屬於何種法 律解釋？', '["文義解釋", "歷史解釋", "體系解釋", "目的解釋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00226', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '依據土地徵收條例相關規定，政府可以徵收人民土地，興建大眾運輸系統，此舉雖侵害人民的財產權，卻 是基於憲法中所提及的何種正當理由，而對人民的基本權利有所限制？', '["增進公共利益", "避免緊急危難", "維持社會秩序", "防止妨礙他人自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00227', 'elementary-f29af906', 'elementary-f29af906-moex-113-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '下列何者為我國憲法本文中規定國民應盡的義務且符合施行現況？', '["具中華民國國籍者應繳納全民健保費用", "滿18歲的全體中華民國國民皆應服兵役", "每位國民應按年度申報營業事業所得稅", "6歲至15歲學齡之國民應接受國民教育"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:51+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
